const input = $json;

// Strava trigger sometimes gives webhook shell + object_data
// Your data shows the useful activity is inside object_data
const activity = input.object_data || input;

// Helpers
function num(value) {
  if (value === undefined || value === null || value === '' || value === 'null') {
    return null;
  }
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function str(value) {
  if (value === undefined || value === null || value === '' || value === 'null') {
    return null;
  }
  return String(value);
}

function milesFromMeters(meters) {
  const m = num(meters);
  return m === null ? null : Number((m / 1609.344).toFixed(2));
}

function minutesFromSeconds(seconds) {
  const s = num(seconds);
  return s === null ? null : Number((s / 60).toFixed(2));
}

function pacePerMile(distanceMeters, movingSeconds) {
  const miles = milesFromMeters(distanceMeters);
  const seconds = num(movingSeconds);

  if (!miles || !seconds) return null;

  const secPerMile = seconds / miles;
  const min = Math.floor(secPerMile / 60);
  const sec = Math.round(secPerMile % 60).toString().padStart(2, '0');

  return `${min}:${sec}/mi`;
}

function elevationFeet(meters) {
  const m = num(meters);
  return m === null ? null : Number((m * 3.28084).toFixed(0));
}

const cleaned = {
  source: 'strava',

  source_activity_id: str(activity.id || input.object_id),

  start_time: str(activity.start_date_local || activity.start_date),

  sport: str(activity.sport_type || activity.type),
  sub_sport: str(activity.workout_type),
  workout_name: str(activity.name),

  distance_miles: milesFromMeters(activity.distance),
  duration_minutes: minutesFromSeconds(activity.moving_time || activity.elapsed_time),
  pace_per_mile: pacePerMile(activity.distance, activity.moving_time || activity.elapsed_time),

  avg_heart_rate: num(activity.average_heartrate),
  max_heart_rate: num(activity.max_heartrate),
  avg_power: num(activity.average_watts),
  calories: num(activity.calories),
  elevation_gain_feet: elevationFeet(activity.total_elevation_gain),

  training_load: num(activity.suffer_score),
  effort_label: 'unknown',

  raw_json: input
};

return [
  {
    json: cleaned
  }
];

