const newestWorkout = $node["Clean Workout Data"].json;
const recentHistory = $items("Postgres - Last 28 Days").map(i => i.json);
const similarWorkouts = $items("Postgres - Similar Workouts").map(i => i.json);
const tomorrowPlan = $items("Postgres - Tomorrow Plan").map(i => i.json)[0] || {
  day_of_week: null,
  planned_sport: "unknown",
  planned_focus: "unknown",
  description: "No plan found for tomorrow."
};

const last7Days = recentHistory.filter(w => {
  if (!w.start_time) return false;
  return new Date(w.start_time).getTime() >= Date.now() - 7 * 24 * 60 * 60 * 1000;
});

const load7 = last7Days.reduce((sum, w) => sum + Number(w.training_load || 0), 0);
const load28 = recentHistory.reduce((sum, w) => sum + Number(w.training_load || 0), 0);

return [{
  json: {
    newest_workout: newestWorkout,
    recent_similar_workouts: similarWorkouts.slice(0, 5),
    tomorrow_plan: tomorrowPlan,
    simple_metrics: {
      workouts_last_7_days: last7Days.length,
      training_load_last_7_days: +load7.toFixed(1),
      training_load_last_28_days: +load28.toFixed(1)
    }
  }
}];

const aiOutput = $json.output || $json.text || $json.response || 'No coach response generated.';
const workout = $node["Clean Workout Data"].json;

const slackText = `${aiOutput}\n\n_This is coaching guidance from your AI agent. Use judgment and adjust based on how you feel._`;

return [{
  json: {
    source_activity_id: workout.source_activity_id,
    slack_text: slackText,
    ai_summary: aiOutput
  }
}];
